export function placeholderImageSummary(limitPerCategory = 3) {
  const groups = placeholderImageCategories.map((category) => {
    const items = placeholderImageLibrary.filter((image) => image.category === category.id).slice(0, limitPerCategory);
    return `${category.id}: ${category.name} slots ${category.slots.join(', ')} -> ${items.map((image) => image.path).join(', ')}`;
  });
  return groups.join('\n');
}

export function findPlaceholderImages({ text = '', category = '', slot = '', limit = 6 } = {}) {
  const haystack = String([text, category, slot].filter(Boolean).join(' ')).toLowerCase();
  const scored = placeholderImageLibrary.map((image) => {
    let score = 0;
    if (category && image.category === category) score += 8;
    if (slot && image.slots.includes(slot)) score += 5;
    if (haystack.includes(image.category)) score += 6;
    image.slots.forEach((item) => { if (haystack.includes(item)) score += 3; });
    image.title.toLowerCase().split(/\W+/).forEach((word) => { if (word.length > 3 && haystack.includes(word)) score += 1; });
    return { image, score };
  });
  return scored.sort((a, b) => b.score - a.score || a.image.path.localeCompare(b.image.path)).slice(0, limit).map((item) => item.image);
}
